@using sv_4a89bd9b4e0f4cbe92a45a19b5294336.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <text>Validating…</text>
        }
        else
        {
            <text>Next</text>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? errorMessage;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            errorMessage = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            isValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            isValidating = false;

            if (!isValid)
            {
                errorMessage = "Please enter a valid email address.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_4a89bd9b4e0f4cbe92a45a19b5294336.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="Entries[index]"
                     Index="index"
                     ShowRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                errorMessage = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_4a89bd9b4e0f4cbe92a45a19b5294336.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Reference="References[index]"
                     Index="index"
                     ShowRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_4a89bd9b4e0f4cbe92a45a19b5294336.Models

<h4 class="mb-3">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application has been received. Your application ID is <strong>#@ApplicationId</strong>.</p>
    </div>
}
else
{
    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(0)'>Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <text>Submitting…</text>
            }
            else
            {
                <text>Submit Application</text>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        errorMessage = null;
        isSubmitting = true;
        StateHasChanged();

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch
        {
            errorMessage = "An error occurred while submitting your application. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

